const item = $input.first().json;
const raw = item.choices?.[0]?.message?.content || '{}';
let scoring = {};
try {
  const m = raw.match(/\{[\s\S]*\}/);
  scoring = m ? JSON.parse(m[0]) : {};
} catch(e) {
  scoring = { icp_score: 0, icp_segment: 'COLD', pain_points: [], error: true };
}
return [{ json: {
  ...item,
  icp_score: scoring.icp_score || 0,
  icp_segment: scoring.icp_segment || 'COLD',
  pain_points: scoring.pain_points || [],
  automation_opportunities: scoring.automation_opportunities || [],
  personalization_hook: scoring.personalization_hook || '',
  recommended_service: scoring.recommended_service || 'n8n_automation',
  email_subject: scoring.email_subject || 'Automatisation pour ' + item.company,
  email_tone: scoring.email_tone || 'professional'
}}];

